declare(strict_types=1);require_once __DIR__.'/../../config/config.php';require_once ROOT_PATH.'/functions/maintenance_functions.php';requireAuth();enforceModuleAccess('maintenance');if($_SERVER['REQUEST_METHOD']==='POST'){if(!verifyCsrfToken((string)($_POST['csrf_token']??''))){setFlash('danger','Invalid form token.');redirect('modules/maintenance/add.php');}[$ok,$result]=saveMaintenance($_POST);setFlash($ok?'success':'danger',$ok?'Maintenance scheduled.':implode(' ',(array)$result));redirect($ok?'modules/maintenance/view.php?id='.$result:'modules/maintenance/add.php');}$vehicles=getDb()->query('SELECT id,registration_number FROM vehicles WHERE deleted_at IS NULL AND status<>"Retired" ORDER BY registration_number')->fetchAll();$pageTitle='Schedule maintenance';require ROOT_PATH.'/includes/header.php';require ROOT_PATH.'/includes/sidebar.php';
?><main class="main-content maintenance-module"><?php require ROOT_PATH.'/includes/navbar.php';?><h1 class="page-title">Schedule maintenance</h1><p class="page-subtitle">Vehicles remain available until work is explicitly started.</p><form class="card dashboard-card maintenance-form" method="post"><input type="hidden" name="csrf_token" value="<?=e(csrfToken())?>"><div class="form-grid"><div class="form-group"><label>Vehicle</label><select name="vehicle_id" required><?php foreach($vehicles as $vehicle):?><option value="<?=$vehicle['id']?>"><?=e($vehicle['registration_number'])?></option><?php endforeach;?></select></div><div class="form-group"><label>Maintenance type</label><select name="maintenance_type"><?php foreach(['Oil Change','Engine Service','Brake Service','Tyre Replacement','Battery Replacement','Insurance Renewal','Fitness Renewal','General Service','Emergency Repair','Custom'] as $type):?><option><?=$type?></option><?php endforeach;?></select></div><div class="form-group"><label>Priority</label><select name="priority"><?php foreach(['Low','Medium','High','Critical'] as $priority):?><option><?=$priority?></option><?php endforeach;?></select></div><div class="form-group"><label>Workshop</label><input name="vendor_name"></div><div class="form-group"><label>Mechanic</label><input name="mechanic_name"></div><div class="form-group"><label>Estimated cost</label><input name="estimated_cost" type="number" min="0" step=".01" required></div><div class="form-group"><label>Scheduled date</label><input name="scheduled_date" type="date" required></div><div class="form-group"><label>Expected completion</label><input name="expected_completion_date" type="date"></div></div><div class="form-group"><label>Description</label><textarea name="description" required></textarea></div><div class="form-group"><label>Remarks</label><textarea name="remarks"></textarea></div><div class="form-actions"><button class="btn btn-primary">Schedule maintenance</button><a class="btn btn-secondary" href="index.php">Cancel</a></div></form></main><?php require ROOT_PATH.'/includes/footer.php';?>
